import React, { useState, useEffect, useCallback } from 'react';
import axios from 'axios';
import { useNavigate } from 'react-router-dom';

const Cart = () => {
    const [cart, setCart] = useState([]);
    const [totalPrice, setTotalPrice] = useState(0);
    const customerId = sessionStorage.getItem("customerid");
    const navigate = useNavigate();

    const fetchCart = useCallback(() => {
        if (customerId) {
            axios.post("http://localhost:3001/customer/viewcart", { customerId })
                .then(response => {
                    if (Array.isArray(response.data)) {
                        setCart(response.data);
                    } else {
                        setCart([]);
                    }
                    setTotalPrice(0); // Always reset total on a fresh fetch.
                })
                .catch(err => {
                    console.error("Error fetching cart:", err);
                    alert("Could not fetch cart items.");
                });
        }
    }, [customerId]);

    useEffect(() => {
        fetchCart();
    }, [fetchCart]);

    const handleQuantityChange = (productId, newQuantity) => {
        const updatedCart = cart.map(item => {
            if (item.productId._id === productId) {
                return { ...item, quantity: newQuantity };
            }
            return item;
        });
        setCart(updatedCart);
    };

    const handleRemoveFromCart = (productId) => {
        axios.post("http://localhost:3001/customer/removefromcart", { customerId, productId })
            .then(response => {
                if (response.data.status === "success") {
                    alert("Product removed from cart.");
                    fetchCart(); // Refresh cart
                } else {
                    alert(response.data.message || "Failed to remove product from cart.");
                }
            })
            .catch(err => {
                console.error("Error removing from cart:", err);
                alert("An error occurred while removing product from cart.");
            });
    };

    const handleCalculateTotal = () => {
        const total = cart.reduce((acc, item) => {
            const quantity = parseInt(item.quantity, 10);
            if (!item || !item.productId || isNaN(quantity) || quantity < 1) return acc;
            return acc + (item.productId.price * quantity);
        }, 0);
        setTotalPrice(total);
    };

    const handlePlaceOrder = () => {
        const items = cart
            .filter(item => item.quantity && parseInt(item.quantity, 10) > 0)
            .map(item => ({
                productId: item.productId._id,
                quantity: parseInt(item.quantity, 10)
            }));

        axios.post("http://localhost:3001/orders", { customerId, items })
            .then(response => {
                if (response.status === 201) {
                    alert("Order placed successfully!");
                    navigate('/my-orders'); // Navigate to orders page for confirmation
                } else {
                    alert(response.data.message || "Failed to place order.");
                }
            })
            .catch(err => {
                console.error("Error placing order:", err);
                alert(err.response?.data?.message || "An error occurred while placing your order.");
            });
    };

    return (
        <div className="container">
            <h2 className="mt-3">Your Cart</h2>
            {cart.length > 0 ? (
                <>
                        <table className="table align-middle mt-4">
                            <thead>
                                <tr>
                                    <th scope="col" style={{ width: '50%' }}>Product</th>
                                    <th scope="col" className="text-center">Price</th>
                                    <th scope="col" className="text-center">Quantity</th>
                                    <th scope="col" className="text-end">Subtotal</th>
                                    <th scope="col" className="text-center"></th>
                                </tr>
                            </thead>
                            <tbody>
                                {cart.map((item) => (
                                    item.productId && (
                                        <tr key={item.productId._id}>
                                            <td>
                                                <h5 className="mb-0">{item.productId.name}</h5>
                                            </td>
                                            <td className="text-center">${item.productId.price.toFixed(2)}</td>
                                            <td className="text-center">
                                                <input
                                                    type="number"
                                                    className="form-control mx-auto"
                                                    style={{ width: '80px' }}
                                                    value={item.quantity}
                                                    onChange={(e) => handleQuantityChange(item.productId._id, e.target.value)}
                                                    min="1"
                                                />
                                            </td>
                                            <td className="text-end">${(item.productId.price * (parseInt(item.quantity, 10) || 0)).toFixed(2)}</td>
                                            <td className="text-center">
                                                <button type="button" className="btn btn-danger btn-sm" onClick={() => handleRemoveFromCart(item.productId._id)}>Remove</button>
                                            </td>
                                        </tr>
                                    )
                                ))}
                            </tbody>
                        </table>
                    <div className="row mt-4">
                        <div className="col text-end">
                            <h3>Total: ${totalPrice.toFixed(2)}</h3>
                            <button type="button" className="btn btn-info me-3" onClick={handleCalculateTotal}>Calculate Total</button>
                            <button type="button" className="btn btn-success btn-lg" onClick={handlePlaceOrder} disabled={totalPrice === 0 || cart.length === 0}>Place Order</button>
                        </div>
                    </div>
                </>
            ) : (
                <div className="text-center mt-5"><p>Your cart is empty.</p></div>
            )}
        </div>
    );
}

export default Cart
